detection.nginx:
# Verify Googlebot — block impersonators
geo $is_google_ip {
    default 0;
    66.249.64.0/19  1;
    66.249.80.0/20  1;
    64.233.160.0/19 1;
    74.125.0.0/16   1;
    209.85.128.0/17 1;
}

map $http_user_agent $is_googlebot_ua {
    default         0;
    ~*[Gg]ooglebot  1;
}

location / {
    # Block if UA says Googlebot but IP is not Google
    set $check "";
    if ($is_googlebot_ua = 1) { set $check "bot_"; }
    if ($is_google_ip = 0)    { set $check "${check}noip"; }
    if ($check = "bot_noip")  { return 403; }
}

# Block AhrefsBot
map $http_user_agent $block_ahrefs {
    default     0;
    ~*AhrefsBot 1;
}

server {
    if ($block_ahrefs) { return 403; }
}

# Block Scrapy scrapers
map $http_user_agent $block_scraper {
    default         0;
    ~*[Ss]crapy     1;
    ~*Python-urllib 1;
}

limit_req_zone $binary_remote_addr zone=scraper_limit:10m rate=30r/m;

server {
    if ($block_scraper) { return 403; }
    location /products/ {
        limit_req zone=scraper_limit burst=5 nodelay;
    }
}

# Verify Bingbot — block impersonators
geo $is_msft_ip {
    default 0;
    40.77.167.0/24  1;
    207.46.0.0/16   1;
    157.54.0.0/15   1;
    65.52.0.0/14    1;
}

map $http_user_agent $is_bingbot {
    default 0;
    ~*bingbot 1;
}

location / {
    set $bcheck "";
    if ($is_bingbot = 1)  { set $bcheck "bot_"; }
    if ($is_msft_ip = 0)  { set $bcheck "${bcheck}noip"; }
    if ($bcheck = "bot_noip") { return 403; }
}

# Block GPTBot AI training crawler
map $http_user_agent $block_gptbot {
    default 0;
    ~*GPTBot 1;
}

server {
    if ($block_gptbot) { return 403; }
    # ChatGPT-User allowed by default (drives referral traffic)
}
